1	/**
2	 * Effect factory registry.
3	 * Register effect factories by type ID, create instances on demand.
4	 */
5	
6	import type { EffectFactory, EffectInstance, EffectRegistry } from "./types";
7	
8	export function createEffectRegistry(): EffectRegistry {
9	  const factories = new Map<string, EffectFactory>();
10	
11	  return {
12	    register(factory: EffectFactory): void {
13	      factories.set(factory.definition.id, factory);
14	    },
15	
16	    get(typeId: string): EffectFactory | undefined {
17	      return factories.get(typeId);
18	    },
19	
20	    getAll(): readonly EffectFactory[] {
21	      return [...factories.values()];
22	    },
23	
24	    create(typeId: string, ctx: AudioContext, id?: string): EffectInstance {
25	      const factory = factories.get(typeId);
26	      if (!factory) {
27	        throw new Error(`Unknown effect type: ${typeId}`);
28	      }
29	      const instanceId = id ?? `${typeId}-${crypto.randomUUID()}`;
30	      return factory.create(ctx, instanceId);
31	    },
32	  };
33	}
