1	/**
2	 * Pre-populated effect registry with all built-in effect factories.
3	 * Single source of truth for available effect types.
4	 */
5	
6	import type { EffectRegistry } from "./types";
7	import { createEffectRegistry } from "./registry";
8	import { createReverbFactory } from "./reverb";
9	import { createDelayFactory } from "./delay";
10	import { createCompressorFactory } from "./compressor";
11	import { createEqFactory } from "./eq";
12	import { createDistortionFactory } from "./distortion";
13	import { createChorusFactory } from "./chorus";
14	
15	export function createDefaultRegistry(): EffectRegistry {
16	  const registry = createEffectRegistry();
17	  registry.register(createReverbFactory());
18	  registry.register(createDelayFactory());
19	  registry.register(createCompressorFactory());
20	  registry.register(createEqFactory());
21	  registry.register(createDistortionFactory());
22	  registry.register(createChorusFactory());
23	  return registry;
24	}
