1	/**
2	 * Delay effect: simple delay with feedback via DelayNode + GainNode.
3	 * Feedback is clamped to <1.0 to prevent runaway oscillation.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const MAX_FEEDBACK = 0.95;
10	
11	const PARAMS: readonly EffectParameterSchema[] = [
12	  {
13	    name: "Time",
14	    key: "time",
15	    min: 0.01,
16	    max: 2,
17	    default: 0.3,
18	    step: 0.01,
19	    unit: "s",
20	  },
21	  {
22	    name: "Feedback",
23	    key: "feedback",
24	    min: 0,
25	    max: MAX_FEEDBACK,
26	    default: 0.4,
27	    step: 0.01,
28	    unit: "",
29	  },
30	  {
31	    name: "Mix",
32	    key: "mix",
33	    min: 0,
34	    max: 100,
35	    default: 30,
36	    step: 1,
37	    unit: "%",
38	  },
39	];
40	
41	export function createDelayFactory(): EffectFactory {
42	  return {
43	    definition: { id: "delay", name: "Delay", parameters: PARAMS },
44	    create(ctx, id) {
45	      let delayNode: DelayNode;
46	      let feedbackGain: GainNode;
47	
48	      return createBaseEffect({
49	        ctx,
50	        id,
51	        typeId: "delay",
52	        params: PARAMS,
53	        buildChain(inputNode, outputNode) {
54	          delayNode = ctx.createDelay(2);
55	          feedbackGain = ctx.createGain();
56	
57	          delayNode.delayTime.value = 0.3;
58	          feedbackGain.gain.value = 0.4;
59	
60	          inputNode.connect(delayNode);
61	          delayNode.connect(outputNode);
62	          delayNode.connect(feedbackGain);
63	          feedbackGain.connect(delayNode);
64	        },
65	        disposeChain() {
66	          delayNode.disconnect();
67	          feedbackGain.disconnect();
68	        },
69	        applyParam(key, value, setMix) {
70	          switch (key) {
71	            case "time":
72	              delayNode.delayTime.value = value;
73	              break;
74	            case "feedback":
75	              feedbackGain.gain.value = Math.min(value, MAX_FEEDBACK);
76	              break;
77	            case "mix":
78	              setMix(value / 100);
79	              break;
80	          }
81	        },
82	      });
83	    },
84	  };
85	}
