1	/**
2	 * Insert chain manager for mixer channel strips.
3	 * Manages a serial chain of effect nodes between source and destination.
4	 * Re-wires the Web Audio graph when inserts are added/removed.
5	 */
6	
7	export type InsertEntry = {
8	  readonly id: string;
9	  readonly input: AudioNode;
10	  readonly output: AudioNode;
11	};
12	
13	export type InsertChain = {
14	  addInsert(id: string, input: AudioNode, output: AudioNode): void;
15	  removeInsert(id: string): void;
16	  getInserts(): readonly InsertEntry[];
17	  dispose(): void;
18	};
19	
20	/** Safe array access for the insert chain */
21	function at(entries: InsertEntry[], i: number): InsertEntry {
22	  const e = entries[i];
23	  if (!e) throw new Error("Insert index out of bounds");
24	  return e;
25	}
26	
27	export function createInsertChain(
28	  source: AudioNode,
29	  dest: AudioNode,
30	): InsertChain {
31	  const inserts: InsertEntry[] = [];
32	
33	  // Track the node source currently connects to, so we can disconnect
34	  // only our connection instead of severing all outgoing connections.
35	  let sourceTarget: AudioNode = dest;
36	
37	  function rewire(): void {
38	    // Disconnect only the chain's own connections
39	    try {
40	      source.disconnect(sourceTarget);
41	    } catch {
42	      // Target already disconnected — safe to ignore
43	    }
44	    for (const entry of inserts) {
45	      entry.output.disconnect();
46	    }
47	
48	    if (inserts.length === 0) {
49	      source.connect(dest);
50	      sourceTarget = dest;
51	      return;
52	    }
53	
54	    // source -> first insert input
55	    const first = at(inserts, 0);
56	    source.connect(first.input);
57	    sourceTarget = first.input;
58	
59	    // Chain inserts: each output -> next input
60	    for (let i = 0; i < inserts.length - 1; i++) {
61	      const current = at(inserts, i);
62	      const next = at(inserts, i + 1);
63	      current.output.connect(next.input);
64	    }
65	
66	    // Last insert output -> dest
67	    const last = at(inserts, inserts.length - 1);
68	    last.output.connect(dest);
69	  }
70	
71	  // Initial wiring: source -> dest
72	  source.connect(dest);
73	
74	  return {
75	    addInsert(id: string, input: AudioNode, output: AudioNode): void {
76	      inserts.push({ id, input, output });
77	      rewire();
78	    },
79	
80	    removeInsert(id: string): void {
81	      const idx = inserts.findIndex((e) => e.id === id);
82	      if (idx === -1) return;
83	      const removed = at(inserts, idx);
84	      removed.output.disconnect();
85	      inserts.splice(idx, 1);
86	      rewire();
87	    },
88	
89	    getInserts(): readonly InsertEntry[] {
90	      return [...inserts];
91	    },
92	
93	    dispose(): void {
94	      try {
95	        source.disconnect(sourceTarget);
96	      } catch {
97	        // Already disconnected
98	      }
99	      for (const entry of inserts) {
100	        entry.output.disconnect();
101	      }
102	      inserts.length = 0;
103	    },
104	  };
105	}
