1	/**
2	 * Zustand store for effects rack state.
3	 * Per-track effect chain stored as serializable state.
4	 */
5	
6	import { create } from "zustand";
7	import type { EffectSlotState } from "./types";
8	
9	export type EffectsStore = {
10	  trackEffects: Record<string, readonly EffectSlotState[]>;
11	
12	  addEffect: (trackId: string, slot: EffectSlotState) => void;
13	  removeEffect: (trackId: string, effectId: string) => void;
14	  updateEffectParam: (
15	    trackId: string,
16	    effectId: string,
17	    key: string,
18	    value: number,
19	  ) => void;
20	  toggleBypass: (trackId: string, effectId: string) => void;
21	  removeTrackEffects: (trackId: string) => void;
22	  reorderEffect: (trackId: string, effectId: string, toIndex: number) => void;
23	  getTrackEffects: (trackId: string) => readonly EffectSlotState[];
24	};
25	
26	export const useEffectsStore = create<EffectsStore>()((set, get) => ({
27	  trackEffects: {},
28	
29	  addEffect(trackId, slot) {
30	    set((s) => {
31	      const existing = s.trackEffects[trackId] ?? [];
32	      return {
33	        trackEffects: {
34	          ...s.trackEffects,
35	          [trackId]: [...existing, slot],
36	        },
37	      };
38	    });
39	  },
40	
41	  removeEffect(trackId, effectId) {
42	    set((s) => {
43	      const existing = s.trackEffects[trackId];
44	      if (!existing) return s;
45	      const next = existing.filter((e) => e.id !== effectId);
46	      if (next.length === 0) {
47	        return {
48	          trackEffects: Object.fromEntries(
49	            Object.entries(s.trackEffects).filter(([k]) => k !== trackId),
50	          ),
51	        };
52	      }
53	      return {
54	        trackEffects: { ...s.trackEffects, [trackId]: next },
55	      };
56	    });
57	  },
58	
59	  updateEffectParam(trackId, effectId, key, value) {
60	    set((s) => {
61	      const existing = s.trackEffects[trackId];
62	      if (!existing) return s;
63	      return {
64	        trackEffects: {
65	          ...s.trackEffects,
66	          [trackId]: existing.map((e) =>
67	            e.id === effectId
68	              ? { ...e, params: { ...e.params, [key]: value } }
69	              : e,
70	          ),
71	        },
72	      };
73	    });
74	  },
75	
76	  toggleBypass(trackId, effectId) {
77	    set((s) => {
78	      const existing = s.trackEffects[trackId];
79	      if (!existing) return s;
80	      return {
81	        trackEffects: {
82	          ...s.trackEffects,
83	          [trackId]: existing.map((e) =>
84	            e.id === effectId ? { ...e, bypassed: !e.bypassed } : e,
85	          ),
86	        },
87	      };
88	    });
89	  },
90	
91	  removeTrackEffects(trackId) {
92	    set((s) => ({
93	      trackEffects: Object.fromEntries(
94	        Object.entries(s.trackEffects).filter(([k]) => k !== trackId),
95	      ),
96	    }));
97	  },
98	
99	  reorderEffect(trackId, effectId, toIndex) {
100	    set((s) => {
101	      const existing = s.trackEffects[trackId];
102	      if (!existing) return s;
103	      const fromIndex = existing.findIndex((e) => e.id === effectId);
104	      if (fromIndex === -1) return s;
105	      const next = [...existing];
106	      const moved = next.splice(fromIndex, 1)[0];
107	      if (moved === undefined) return s;
108	      next.splice(toIndex, 0, moved);
109	      return {
110	        trackEffects: {
111	          ...s.trackEffects,
112	          [trackId]: next,
113	        },
114	      };
115	    });
116	  },
117	
118	  getTrackEffects(trackId) {
119	    return get().trackEffects[trackId] ?? [];
120	  },
121	}));
