73	  return {
74	    trackId,
75	    inputGain,
76	    inserts: [],
77	    preFaderTap,
78	    faderGain,
79	    panner,
80	    muteGain,
81	    analyser,
82	    muted: false,
83	    solo: false,
84	    soloIsolate: false,
