202	    },
203	
204	    addInsert(
205	      trackId: string,
206	      id: string,
207	      input: AudioNode,
208	      output: AudioNode,
209	    ): void {
210	      const chain = insertChains.get(trackId);
211	      chain?.addInsert(id, input, output);
212	    },
213	
214	    removeInsert(trackId: string, insertId: string): void {
215	      const chain = insertChains.get(trackId);
216	      chain?.removeInsert(insertId);
217	    },
218	
219	    emergencyMute(): void {
220	      master.faderGain.gain.value = 0;
221	    },
222	
223	    releaseEmergencyMute(): void {
224	      master.faderGain.gain.value = savedMasterLevel;
225	    },
226	
227	    dispose(): void {
228	      for (const chain of insertChains.values()) {
229	        chain.dispose();
230	      }
231	      insertChains.clear();
232	      for (const strip of strips.values()) {
233	        strip.inputGain.disconnect();
234	        strip.preFaderTap.disconnect();
235	        strip.faderGain.disconnect();
236	        strip.panner.disconnect();
237	        strip.muteGain.disconnect();
238	        strip.analyser.disconnect();
239	      }
240	      strips.clear();
241	      master.inputGain.disconnect();
242	      master.faderGain.disconnect();
243	      master.limiter.disconnect();
244	      master.analyser.disconnect();
245	    },
246	  };
247	
248	  return engine;
249	}

1	/**
2	 * Provider that creates the effects bridge, mixer engine, and registry.
3	 * Bridges the effects Zustand store to live Web Audio nodes.
4	 */
5	
6	import { createContext, useContext, useEffect, useRef, useState } from "react";
7	import { useAudioEngine } from "@audio/use-audio-engine";
8	import { createMixerEngine, type MixerEngine } from "@audio/mixer";
9	import type { EffectRegistry } from "./types";
10	import { createDefaultRegistry } from "./default-registry";
11	import { createEffectsBridge, type EffectsBridge } from "./effects-bridge";
12	
13	type EffectsBridgeContext = {
14	  readonly registry: EffectRegistry;
15	  readonly mixer: MixerEngine;
16	  readonly bridge: EffectsBridge;
17	};
18	
19	const Ctx = createContext<EffectsBridgeContext | null>(null);
20	
21	export function EffectsBridgeProvider({
22	  children,
23	}: {
24	  children: React.ReactNode;
25	}): React.JSX.Element {
26	  const engine = useAudioEngine();
27	
28	  const [value] = useState<EffectsBridgeContext>(() => {
29	    const registry = createDefaultRegistry();
30	    const mixer = createMixerEngine(engine.ctx);
31	    const bridge = createEffectsBridge(engine.ctx, registry, mixer);
32	    return { registry, mixer, bridge };
33	  });
34	
35	  // Guard against StrictMode double-mount: only dispose on true unmount.
36	  // useState initializers are called once and cached in React 18/19,
37	  // so the deferred check is sufficient — no duplicate instances are created.
38	  const mountedRef = useRef(true);
39	  useEffect(() => {
40	    mountedRef.current = true;
41	    return () => {
42	      mountedRef.current = false;
43	      // Defer disposal so StrictMode re-mount can cancel it
44	      setTimeout(() => {
45	        if (!mountedRef.current) {
46	          value.bridge.dispose();
47	          value.mixer.dispose();
48	        }
49	      }, 0);
50	    };
51	  }, [value]);
52	
53	  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
54	}
55	
56	export function useEffectsBridgeContext(): EffectsBridgeContext {
57	  const ctx = useContext(Ctx);
58	  if (ctx === null) {
59	    throw new Error(
60	      "useEffectsBridgeContext must be used within EffectsBridgeProvider",
61	    );
62	  }
63	  return ctx;
64	}
