5	
6	export type InsertSlot = {
7	  readonly id: string;
8	  readonly node: AudioNode | null; // null = empty slot
9	  readonly bypassed: boolean;
10	};
11	
12	export type ChannelStrip = {
13	  readonly trackId: string;
14	  /** Pre-insert input gain */
15	  readonly inputGain: GainNode;
16	  /** Ordered insert chain (empty initially) */
17	  readonly inserts: readonly InsertSlot[];
18	  /** Pre-fader tap point for pre-fader sends (after inserts, before fader) */
19	  readonly preFaderTap: GainNode;
20	  /** Post-insert fader (logarithmic taper via GainNode) */
21	  readonly faderGain: GainNode;
22	  /** Stereo panner */
23	  readonly panner: StereoPannerNode;
24	  /** Mute control (gain 0 or 1) */
25	  readonly muteGain: GainNode;
26	  /** AnalyserNode for metering */
27	  readonly analyser: AnalyserNode;
28	  /** Whether this channel is muted */
29	  muted: boolean;
30	  /** Whether this channel is soloed */
31	  solo: boolean;
32	  /** Whether this channel has solo-isolate enabled */
33	  soloIsolate: boolean;
34	};
35	
36	export type MasterBus = {
37	  /** Sum input from all channel strips */
38	  readonly inputGain: GainNode;
39	  /** Master fader */
40	  readonly faderGain: GainNode;
