            key={p.key}
            paramKey={p.key}
            label={p.name}
            min={p.min}
            max={p.max}
            step={p.step}
            value={params[p.key] ?? p.default}
            onChange={onParamChange}
          />
        ))}
      </div>
    </div>
  );
}

type ParamKnobProps = {
  paramKey: string;
  label: string;
  min: number;
  max: number;
  step: number;
  value: number;
  onChange: (key: string, value: number) => void;
};

function ParamKnob({
  paramKey,
  label,
  min,
  max,
  step,
  value,
  onChange,
}: ParamKnobProps): React.JSX.Element {
  const handleChange = useCallback(
    (v: number) => {
      onChange(paramKey, v);
    },
    [paramKey, onChange],
  );

  return (
    <RotaryKnob
      value={value}
      min={min}
      max={max}
      step={step}
      onChange={handleChange}
      label={label}
      size={36}
    />
  );
}

