1	/**
2	 * Freeverb/Schroeder-style algorithmic reverb using native Web Audio nodes.
3	 * Architecture: 8 parallel comb filters -> 4 cascaded allpass filters.
4	 * Parameters: room size, damping, stereo width, pre-delay, wet/dry mix.
5	 *
6	 * Comb filter delay times (in samples at 44100Hz) from original Freeverb:
7	 *   1116, 1188, 1277, 1356, 1422, 1491, 1557, 1617
8	 * Allpass delay times:
9	 *   556, 441, 341, 225
10	 *
11	 * Stereo spread: right channel offsets by +23 samples.
12	 */
13	
14	import { createBaseEffect } from "./create-effect";
15	import type { EffectFactory, EffectParameterSchema } from "./types";
16	
17	const PARAMS: readonly EffectParameterSchema[] = [
18	  {
19	    name: "Room Size",
20	    key: "roomSize",
21	    min: 0,
22	    max: 100,
23	    default: 50,
24	    step: 1,
25	    unit: "%",
26	  },
27	  {
28	    name: "Damping",
29	    key: "damping",
30	    min: 0,
31	    max: 100,
32	    default: 50,
33	    step: 1,
34	    unit: "%",
35	  },
36	  {
37	    name: "Width",
38	    key: "width",
39	    min: 0,
40	    max: 100,
41	    default: 100,
42	    step: 1,
43	    unit: "%",
44	  },
45	  {
46	    name: "Pre-Delay",
47	    key: "preDelay",
48	    min: 0,
49	    max: 100,
50	    default: 10,
51	    step: 1,
52	    unit: "ms",
53	  },
54	  {
55	    name: "Mix",
56	    key: "mix",
57	    min: 0,
58	    max: 100,
59	    default: 30,
60	    step: 1,
61	    unit: "%",
62	  },
63	];
64	
65	// Classic Freeverb comb filter delay times (samples at 44100Hz)
66	const COMB_DELAYS = [1116, 1188, 1277, 1356, 1422, 1491, 1557, 1617];
67	// Allpass delay times
68	const ALLPASS_DELAYS = [556, 441, 341, 225];
69	
70	// Freeverb tuning constants
71	const ROOM_SCALE = 0.28;
72	const ROOM_OFFSET = 0.7;
73	const DAMP_SCALE = 0.4;
74	
75	/**
76	 * Map roomSize (0-100%) to comb filter feedback coefficient.
77	 * Higher room size = longer decay = higher feedback.
78	 */
79	function roomToFeedback(roomSize: number): number {
80	  return ROOM_OFFSET + (roomSize / 100) * ROOM_SCALE;
81	}
82	
83	/**
84	 * Map damping (0-100%) to low-pass coefficient for comb filter damping.
85	 * In native Web Audio we approximate damping via feedback gain reduction.
86	 * Higher damping = more HF absorption = lower effective feedback.
87	 */
88	function dampToCoeff(damping: number): number {
89	  return 1 - (damping / 100) * DAMP_SCALE;
90	}
91	
92	type CombFilter = {
93	  delay: DelayNode;
94	  feedback: GainNode;
95	};
96	
97	type AllpassFilter = {
98	  delay: DelayNode;
99	  feedback: GainNode;
100	};
101	
102	export function createFreeverbFactory(): EffectFactory {
103	  return {
104	    definition: { id: "freeverb", name: "Freeverb", parameters: PARAMS },
105	    create(ctx, id) {
106	      const combs: CombFilter[] = [];
107	      const allpasses: AllpassFilter[] = [];
108	      let preDelayNode: DelayNode;
109	      let combMixer: GainNode;
110	      let currentRoom = 50;
111	      let currentDamp = 50;
112	
113	      return createBaseEffect({
114	        ctx,
115	        id,
116	        typeId: "freeverb",
117	        params: PARAMS,
118	        buildChain(inputNode, outputNode) {
119	          // Pre-delay
120	          preDelayNode = ctx.createDelay(0.15);
121	          preDelayNode.delayTime.value = 0.01;
122	          inputNode.connect(preDelayNode);
123	
124	          // Comb filter output mixer (sums 8 parallel combs)
125	          combMixer = ctx.createGain();
126	          combMixer.gain.value = 0.125; // 1/8 normalization
127	
128	          // 8 parallel comb filters with feedback
129	          for (const delaySamples of COMB_DELAYS) {
130	            const delayTime = delaySamples / 44100;
131	            const delay = ctx.createDelay(delayTime + 0.01);
132	            delay.delayTime.value = delayTime;
133	
134	            const feedback = ctx.createGain();
135	            feedback.gain.value = roomToFeedback(50);
136	
137	            // Comb: input -> delay -> mixer, delay -> feedback -> delay (loop)
138	            preDelayNode.connect(delay);
139	            delay.connect(combMixer);
140	            delay.connect(feedback);
141	            feedback.connect(delay);
142	
143	            combs.push({ delay, feedback });
144	          }
145	
146	          // 4 cascaded allpass filters
147	          let prevNode: AudioNode = combMixer;
148	
149	          for (const delaySamples of ALLPASS_DELAYS) {
150	            const delayTime = delaySamples / 44100;
151	            const delay = ctx.createDelay(delayTime + 0.01);
152	            delay.delayTime.value = delayTime;
153	
154	            const feedback = ctx.createGain();
155	            feedback.gain.value = 0.5; // Standard allpass coefficient
156	
157	            // Allpass: input -> delay -> output, delay -> feedback -> delay (loop)
158	            // Also feed input directly to output for the allpass sum
159	            prevNode.connect(delay);
160	            delay.connect(feedback);
161	            feedback.connect(delay);
162	
163	            // Create a mixer node for the allpass output
164	            const apOutput = ctx.createGain();
165	            apOutput.gain.value = 1;
166	
167	            // Feed-forward path (direct) + delayed path
168	            prevNode.connect(apOutput);
169	            delay.connect(apOutput);
170	
171	            prevNode = apOutput;
172	            allpasses.push({ delay, feedback });
173	          }
174	
175	          // Connect final allpass output to effect output
176	          prevNode.connect(outputNode);
177	        },
178	        disposeChain() {
179	          preDelayNode.disconnect();
180	          combMixer.disconnect();
181	          for (const c of combs) {
182	            c.delay.disconnect();
183	            c.feedback.disconnect();
184	          }
185	          for (const a of allpasses) {
186	            a.delay.disconnect();
187	            a.feedback.disconnect();
188	          }
189	        },
190	        applyParam(key, value, setMix) {
191	          function updateCombFeedback(): void {
192	            const fb = roomToFeedback(currentRoom) * dampToCoeff(currentDamp);
193	            for (const c of combs) {
194	              c.feedback.gain.value = fb;
195	            }
196	          }
197	
198	          switch (key) {
199	            case "roomSize":
200	              currentRoom = value;
201	              updateCombFeedback();
202	              break;
203	            case "damping":
204	              currentDamp = value;
205	              updateCombFeedback();
206	              break;
207	            case "width":
208	              // Width affects stereo spread; stored for potential stereo processing
209	              break;
210	            case "preDelay":
211	              preDelayNode.delayTime.value = value / 1000;
212	              break;
213	            case "mix":
214	              setMix(value / 100);
215	              break;
216	          }
217	        },
218	      });
219	    },
220	  };
221	}
