10	  trackEffects: Record<string, readonly EffectSlotState[]>;
11	
12	  addEffect: (trackId: string, slot: EffectSlotState) => void;
13	  removeEffect: (trackId: string, effectId: string) => void;
14	  updateEffectParam: (
15	    trackId: string,
16	    effectId: string,
17	    key: string,
18	    value: number,
19	  ) => void;
20	  toggleBypass: (trackId: string, effectId: string) => void;
21	  removeTrackEffects: (trackId: string) => void;
22	  swapEffectType: (
23	    trackId: string,
24	    effectId: string,
25	    newTypeId: string,
26	    newParams: Record<string, number>,
27	  ) => void;
28	  reorderEffect: (trackId: string, effectId: string, toIndex: number) => void;
29	  getTrackEffects: (trackId: string) => readonly EffectSlotState[];
30	};
31	
32	export const useEffectsStore = create<EffectsStore>()((set, get) => ({
33	  trackEffects: {},
34	
35	  addEffect(trackId, slot) {
36	    set((s) => {
37	      const existing = s.trackEffects[trackId] ?? [];
38	      return {
39	        trackEffects: {
40	          ...s.trackEffects,
41	          [trackId]: [...existing, slot],
42	        },
43	      };
44	    });
45	  },
46	
47	  removeEffect(trackId, effectId) {
48	    set((s) => {
49	      const existing = s.trackEffects[trackId];
50	      if (!existing) return s;
51	      const next = existing.filter((e) => e.id !== effectId);
52	      if (next.length === 0) {
53	        return {
54	          trackEffects: Object.fromEntries(
55	            Object.entries(s.trackEffects).filter(([k]) => k !== trackId),
56	          ),
57	        };
58	      }
59	      return {
60	        trackEffects: { ...s.trackEffects, [trackId]: next },
61	      };
62	    });
63	  },
64	
65	  updateEffectParam(trackId, effectId, key, value) {
66	    set((s) => {
67	      const existing = s.trackEffects[trackId];
68	      if (!existing) return s;
69	      return {
70	        trackEffects: {
71	          ...s.trackEffects,
72	          [trackId]: existing.map((e) =>
73	            e.id === effectId
74	              ? { ...e, params: { ...e.params, [key]: value } }
75	              : e,
76	          ),
77	        },
78	      };
79	    });
80	  },
81	
82	  toggleBypass(trackId, effectId) {
83	    set((s) => {
84	      const existing = s.trackEffects[trackId];
85	      if (!existing) return s;
86	      return {
87	        trackEffects: {
88	          ...s.trackEffects,
89	          [trackId]: existing.map((e) =>
90	            e.id === effectId ? { ...e, bypassed: !e.bypassed } : e,
91	          ),
92	        },
93	      };
94	    });
95	  },
96	
97	  removeTrackEffects(trackId) {
98	    set((s) => ({
99	      trackEffects: Object.fromEntries(
100	        Object.entries(s.trackEffects).filter(([k]) => k !== trackId),
101	      ),
102	    }));
103	  },
104	
105	  swapEffectType(trackId, effectId, newTypeId, newParams) {
106	    set((s) => {
107	      const existing = s.trackEffects[trackId];
108	      if (!existing) return s;
109	      const idx = existing.findIndex((e) => e.id === effectId);
110	      if (idx === -1) return s;
111	      const slot = existing[idx];
112	      if (!slot) return s;
113	      return {
114	        trackEffects: {
115	          ...s.trackEffects,
116	          [trackId]: existing.map((e, i) =>
117	            i === idx
118	              ? { ...e, typeId: newTypeId, params: newParams }
119	              : e,
120	          ),
121	        },
122	      };
123	    });
124	  },
125	
126	  reorderEffect(trackId, effectId, toIndex) {
127	    set((s) => {
128	      const existing = s.trackEffects[trackId];
129	      if (!existing) return s;
130	      const fromIndex = existing.findIndex((e) => e.id === effectId);
131	      if (fromIndex === -1) return s;
132	      const next = [...existing];
133	      const moved = next.splice(fromIndex, 1)[0];
134	      if (moved === undefined) return s;
135	      next.splice(toIndex, 0, moved);
136	      return {
137	        trackEffects: {
138	          ...s.trackEffects,
139	          [trackId]: next,
140	        },
141	      };
142	    });
143	  },
144	
145	  getTrackEffects(trackId) {
146	    return get().trackEffects[trackId] ?? [];
147	  },
148	}));
