1	/**
2	 * Bridge between effects Zustand store and Web Audio instances.
3	 * Subscribes to store changes, creates/disposes EffectInstances,
4	 * and wires them into the MixerEngine's insert chains.
5	 */
6	
7	import type { EffectInstance, EffectRegistry } from "./types";
8	import type { MixerEngine } from "@audio/mixer";
9	import { useEffectsStore } from "@state/effects";
10	import type { EffectSlotState } from "@state/effects";
11	
12	export type EffectsBridge = {
13	  /** Get a live audio instance by effect ID */
14	  getInstance(effectId: string): EffectInstance | undefined;
15	  /** Tear down all instances and unsubscribe */
16	  dispose(): void;
17	};
18	
19	export function createEffectsBridge(
20	  ctx: AudioContext,
21	  registry: EffectRegistry,
22	  mixer: MixerEngine,
23	): EffectsBridge {
24	  const instances = new Map<string, EffectInstance>();
25	  const effectTrackMap = new Map<string, string>();
26	
27	  function syncSlot(trackId: string, slot: EffectSlotState): void {
28	    const existing = instances.get(slot.id);
29	    if (existing) {
30	      // Detect type swap: destroy old instance and fall through to creation
31	      if (existing.typeId !== slot.typeId) {
32	        removeInstance(slot.id);
33	      } else {
34	        // Sync params
35	        for (const [key, value] of Object.entries(slot.params)) {
36	          if (existing.getParam(key) !== value) {
37	            existing.setParam(key, value);
38	          }
39	        }
40	        // Sync bypass
41	        if (existing.bypassed !== slot.bypassed) {
42	          existing.setBypassed(slot.bypassed);
43	        }
44	        return;
45	      }
46	    }
47	
48	    // Create new instance via registry
49	    const instance = registry.create(slot.typeId, ctx, slot.id);
50	    instances.set(slot.id, instance);
51	    effectTrackMap.set(slot.id, trackId);
52	
53	    // Apply initial state
54	    for (const [key, value] of Object.entries(slot.params)) {
55	      instance.setParam(key, value);
56	    }
57	    instance.setBypassed(slot.bypassed);
58	
59	    // Ensure channel strip exists, then wire insert
60	    mixer.getOrCreateStrip(trackId);
61	    mixer.addInsert(trackId, slot.id, instance.input, instance.output);
62	  }
63	
64	  function removeInstance(effectId: string): void {
65	    const instance = instances.get(effectId);
66	    if (!instance) return;
67	
68	    const trackId = effectTrackMap.get(effectId);
69	    if (trackId !== undefined && trackId !== "") {
70	      mixer.removeInsert(trackId, effectId);
71	    }
72	
73	    instance.dispose();
74	    instances.delete(effectId);
75	    effectTrackMap.delete(effectId);
76	  }
77	
78	  function sync(): void {
79	    const state = useEffectsStore.getState();
80	    const activeIds = new Set<string>();
81	
82	    for (const [trackId, slots] of Object.entries(state.trackEffects)) {
83	      for (const slot of slots) {
84	        activeIds.add(slot.id);
85	        syncSlot(trackId, slot);
86	      }
87	    }
88	
89	    // Remove instances no longer in store
90	    for (const id of [...instances.keys()]) {
91	      if (!activeIds.has(id)) {
92	        removeInstance(id);
93	      }
94	    }
95	  }
96	
97	  // Initial sync
98	  sync();
99	
100	  // Subscribe to store changes
101	  const unsub = useEffectsStore.subscribe(sync);
102	
103	  return {
104	    getInstance(effectId) {
105	      return instances.get(effectId);
106	    },
107	    dispose() {
108	      unsub();
109	      for (const id of [...instances.keys()]) {
110	        removeInstance(id);
111	      }
112	    },
113	  };
114	}
