1	/**
2	 * Reverb effect using ConvolverNode with generated impulse responses.
3	 * Generates exponentially decaying noise IR at the requested decay time.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const PARAMS: readonly EffectParameterSchema[] = [
10	  {
11	    name: "Decay",
12	    key: "decay",
13	    min: 0.1,
14	    max: 10,
15	    default: 2,
16	    step: 0.1,
17	    unit: "s",
18	  },
19	  {
20	    name: "Pre-Delay",
21	    key: "preDelay",
22	    min: 0,
23	    max: 100,
24	    default: 10,
25	    step: 1,
26	    unit: "ms",
27	  },
28	  {
29	    name: "Mix",
30	    key: "mix",
31	    min: 0,
32	    max: 100,
33	    default: 30,
34	    step: 1,
35	    unit: "%",
36	  },
37	];
38	
39	function generateImpulseResponse(
40	  ctx: AudioContext,
41	  decaySeconds: number,
42	): AudioBuffer {
43	  const sampleRate = ctx.sampleRate;
44	  const length = Math.floor(sampleRate * decaySeconds);
45	  const buffer = ctx.createBuffer(2, length, sampleRate);
46	
47	  for (let ch = 0; ch < 2; ch++) {
48	    const data = buffer.getChannelData(ch);
49	    for (let i = 0; i < length; i++) {
50	      const t = i / sampleRate;
51	      // Exponential decay envelope * white noise
52	      data[i] = (Math.random() * 2 - 1) * Math.exp((-3 * t) / decaySeconds);
53	    }
54	  }
55	  return buffer;
56	}
57	
58	export function createReverbFactory(): EffectFactory {
59	  return {
60	    definition: { id: "reverb", name: "Reverb", parameters: PARAMS },
61	    create(ctx, id) {
62	      let convolver: ConvolverNode;
63	      let preDelayNode: DelayNode;
64	      let irTimer: ReturnType<typeof setTimeout> | undefined;
65	
66	      return createBaseEffect({
67	        ctx,
68	        id,
69	        typeId: "reverb",
70	        params: PARAMS,
71	        buildChain(inputNode, outputNode) {
72	          preDelayNode = ctx.createDelay(0.15);
73	          convolver = ctx.createConvolver();
74	          convolver.buffer = generateImpulseResponse(ctx, 2);
75	
76	          inputNode.connect(preDelayNode);
77	          preDelayNode.connect(convolver);
78	          convolver.connect(outputNode);
79	        },
80	        disposeChain() {
81	          clearTimeout(irTimer);
82	          preDelayNode.disconnect();
83	          convolver.disconnect();
84	        },
85	        applyParam(key, value, setMix) {
86	          switch (key) {
87	            case "decay":
88	              // Debounce IR generation — expensive at high decay values
89	              clearTimeout(irTimer);
90	              irTimer = setTimeout(() => {
91	                convolver.buffer = generateImpulseResponse(ctx, value);
92	              }, 80);
93	              break;
94	            case "preDelay":
95	              preDelayNode.delayTime.value = value / 1000;
96	              break;
97	            case "mix":
98	              setMix(value / 100);
99	              break;
100	          }
101	        },
102	      });
103	    },
104	  };
105	}
