1	/**
2	 * Freeverb/Schroeder-style algorithmic reverb using native Web Audio nodes.
3	 * Architecture: 8 parallel comb filters -> 4 cascaded allpass filters.
4	 * Parameters: room size, damping, stereo width, pre-delay, wet/dry mix.
5	 *
6	 * Comb filter delay times (in samples at 44100Hz) from original Freeverb:
7	 *   1116, 1188, 1277, 1356, 1422, 1491, 1557, 1617
8	 * Allpass delay times:
9	 *   556, 441, 341, 225
10	 *
11	 * Stereo spread: right channel offsets by +23 samples.
12	 */
13	
14	import { createBaseEffect } from "./create-effect";
15	import type { EffectFactory, EffectParameterSchema } from "./types";
16	
17	const PARAMS: readonly EffectParameterSchema[] = [
18	  {
19	    name: "Room Size",
20	    key: "roomSize",
21	    min: 0,
22	    max: 100,
23	    default: 50,
24	    step: 1,
25	    unit: "%",
26	  },
27	  {
28	    name: "Damping",
29	    key: "damping",
30	    min: 0,
31	    max: 100,
32	    default: 50,
33	    step: 1,
34	    unit: "%",
35	  },
36	  {
37	    name: "Width",
38	    key: "width",
39	    min: 0,
40	    max: 100,
41	    default: 100,
42	    step: 1,
43	    unit: "%",
44	  },
45	  {
46	    name: "Pre-Delay",
47	    key: "preDelay",
48	    min: 0,
49	    max: 100,
50	    default: 10,
51	    step: 1,
52	    unit: "ms",
53	  },
54	  {
55	    name: "Mix",
56	    key: "mix",
57	    min: 0,
58	    max: 100,
59	    default: 30,
60	    step: 1,
61	    unit: "%",
62	  },
63	];
